                <span className="text-lg font-bold w-8 text-center">{optForm.qty}</span>
                <button onClick={() => setOptForm(f => ({ ...f, qty: f.qty + 1 }))} className="w-8 h-8 rounded-lg bg-cafe-100 flex items-center justify-center hover:bg-cafe-200"><Plus className="w-4 h-4" /></button>
              </div>
