              Tạm tính: <span className="font-bold text-cafe-800">{formatCurrency(optTotal)}</span>
            </div>

            <div className="flex gap-2">
              <button onClick={() => { setOptionModal(null); setEditCartItemId(null); }} className="btn-secondary flex-1">Hủy</button>
              <button onClick={handleSaveCartItem} className="btn-primary flex-1">{editCartItemId ? 'Cập nhật' : 'Thêm vào order'}</button>
            </div>
