            <p className="text-xs text-cafe-500">Bàn: <span className="font-semibold text-cafe-800">{selectedTable?.name}</span></p>
            <div className="space-y-1 text-sm text-cafe-600">
              {cart.map(c => (
                <div key={c.id} className="flex justify-between">
                  <span className="truncate max-w-[60%]">{c.item.name}{c.size ? ` (${c.size.name})` : ''} x{c.quantity}</span>
                  <span className="font-medium text-cafe-800">{formatCurrency(calcCartItem(c))}</span>
                </div>
              ))}
            </div>
            <div className="border-t border-cafe-200 pt-2 mt-2 space-y-1 text-xs text-cafe-500">
              <div className="flex justify-between"><span>Tạm tính</span><span>{formatCurrency(baseSubtotal)}</span></div>
              {toppingSubtotal > 0 && <div className="flex justify-between"><span>Topping</span><span>{formatCurrency(toppingSubtotal)}</span></div>}
              <div className="flex justify-between"><span>Giảm giá</span><span>—</span></div>
              <div className="flex justify-between"><span>Thuế</span><span>—</span></div>
            </div>
            <div className="flex justify-between text-base font-bold text-cafe-800 border-t border-cafe-300 pt-2 mt-1">
              <span>Tổng thanh toán</span>
              <span className="text-cafe-700">{formatCurrency(cartTotal)}</span>
            </div>
          </div>

          <div>
            <label className="label-funcafe">Phương thức thanh toán</label>
            <div className="grid grid-cols-2 gap-2">
              {[
                { value: 'cash', label: '💵 Tiền mặt' },
                { value: 'bank_transfer', label: '🏦 Chuyển khoản' },
                { value: 'qr_code', label: '📱 QR Code' },
                { value: 'e_wallet', label: '👛 Ví điện tử' },
              ].map(m => (
                <button key={m.value} onClick={() => setPaymentMethod(m.value)}
                  className={`px-3 py-2.5 rounded-lg border text-sm font-medium transition-all ${
                    paymentMethod === m.value ? 'border-cafe-700 bg-cafe-50 text-cafe-700 ring-1 ring-cafe-700' : 'border-cafe-200 text-cafe-600 hover:border-cafe-300'
                  }`}>{m.label}</button>
              ))}
            </div>
          </div>

          {paymentMethod === 'cash' && (
            <div>
              <label className="label-funcafe">Tiền khách đưa (đ)</label>
              <input type="text" className="input-funcafe" placeholder="0" value={cashGiven} onChange={e => setCashGiven(e.target.value)} />
              {Number(cashGiven.replace(/\D/g, '')) > 0 && cashChange >= 0 && <p className="text-sm text-green-600 font-medium mt-1">Tiền thối: {formatCurrency(cashChange)}</p>}
              {Number(cashGiven.replace(/\D/g, '')) > 0 && cashChange < 0 && <p className="text-sm text-red-500 mt-1">Chưa đủ {formatCurrency(Math.abs(cashChange))}</p>}
            </div>
          )}

          {paymentMethod === 'qr_code' && (
            <div className="bg-cafe-50 rounded-xl p-4 flex flex-col items-center gap-2">
              <div className="w-28 h-28 bg-white border-2 border-cafe-200 rounded-xl flex items-center justify-center text-cafe-300 text-xs font-mono">QR</div>
              <p className="text-xs text-cafe-500">Quét mã QR để thanh toán</p>
            </div>
          )}

          <div className="flex gap-2 pt-2">
            <button onClick={() => setPaymentModal(false)} className="btn-secondary flex-1">Hủy</button>
            <button onClick={handlePayment} className="btn-primary flex-1 flex items-center justify-center gap-2"><CreditCard className="w-4 h-4" />Xác nhận thanh toán</button>
          </div>
        </div>
      </Modal>

      <ConfirmModal
        open={clearConfirm}
        onClose={() => setClearConfirm(false)}
        onConfirm={async () => {
          if (selectedTable) {
            const existingId = draftOrderIds[selectedTable.id];
            if (existingId) {
              try { await orderService.update(existingId, { tableId: selectedTable.id, items: [], subtotal: 0, discountAmount: 0, taxAmount: 0, totalAmount: 0 }); } catch {}
              setDraftOrderIds(prev => { const { [selectedTable.id]: _, ...rest } = prev; return rest; });
              setActiveOrders(prev => prev.filter(o => o.id !== existingId));
            }
            clearCartForTable(selectedTable.id);
          }
          setSelectedTable(null);
          setClearConfirm(false);
        }}
        title="Hủy order"
        message="Bạn có chắc muốn hủy toàn bộ order hiện tại? Các món đã chọn sẽ bị xóa."
        confirmLabel="Hủy order"
        danger
      />

      {/* Success Modal */}
      <Modal open={!!successModal} onClose={() => setSuccessModal(null)} title="Thanh toán thành công" size="sm">
        {successModal && (
          <div className="text-center space-y-4">
            <div className="flex justify-center">
              <div className="w-16 h-16 bg-green-100 rounded-full flex items-center justify-center"><CheckCircle2 className="w-9 h-9 text-green-500" /></div>
            </div>
            <div>
              <p className="text-cafe-500 text-sm">Mã hóa đơn</p>
              <p className="text-2xl font-bold text-cafe-800 font-mono">{successModal.code}</p>
            </div>
            <div className="bg-cafe-50 rounded-xl py-3 px-4">
              <p className="text-cafe-500 text-xs">Tổng thanh toán</p>
              <p className="text-xl font-bold text-cafe-700">{formatCurrency(successModal.total)}</p>
            </div>
            <div className="flex gap-2 pt-2">
              {/* BUG-12 FIX: Nút in mở trang hóa đơn thay vì chỉ đóng modal */}
              <button onClick={() => { setSuccessModal(null); window.open('/user/invoices', '_blank'); }} className="btn-secondary flex-1 text-sm">In hóa đơn</button>
              <button onClick={() => setSuccessModal(null)} className="btn-primary flex-1 text-sm">Tạo order mới</button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
